import { Text } from "ink";
import React from "react";

import { useTheme } from "@/components/ui/theme-provider";
import { useAnimation } from "@/hooks/use-animation";

export type SpinnerStyle =
  | "dots"
  | "line"
  | "star"
  | "clock"
  | "bounce"
  | "bar"
  | "arc"
  | "arrow"
  | "toggle"
  | "box"
  | "pipe"
  | "earth";

const FRAMES: Record<SpinnerStyle, string[]> = {
  arc: ["в—ң", "в— ", "в—қ", "в—һ", "в—Ў", "в—ҹ"],
  arrow: ["вҶҗ", "вҶ–", "вҶ‘", "вҶ—", "вҶ’", "вҶҳ", "вҶ“", "вҶҷ"],
  bar: ["в–Ҹ", "в–Һ", "в–Қ", "в–Ң", "в–Ӣ", "в–Ҡ", "в–ү", "в–Ҳ", "в–ү", "в–Ҡ", "в–Ӣ", "в–Ң", "в–Қ", "в–Һ"],
  bounce: ["в Ғ", "в Ӯ", "в „", "вЎҖ", "вЎҲ", "в  ", "в җ", "в Ҳ"],
  box: ["в––", "в–ҳ", "в–қ", "в–—"],
  clock: [
    "рҹ•җ",
    "рҹ•‘",
    "рҹ•’",
    "рҹ•“",
    "рҹ•”",
    "рҹ••",
    "рҹ•–",
    "рҹ•—",
    "рҹ•ҳ",
    "рҹ•ҷ",
    "рҹ•ҡ",
    "рҹ•ӣ",
  ],
  dots: ["в Ӣ", "в ҷ", "в №", "в ё", "в ј", "в ҙ", "в Ұ", "в §", "в Ү", "в Ҹ"],
  earth: ["рҹҢҚ", "рҹҢҺ", "рҹҢҸ"],
  line: ["вҖ”", "\\", "|", "/"],
  pipe: ["в”Ө", "в”ҳ", "в”ҙ", "в””", "в”ң", "в”Ң", "в”¬", "в”җ"],
  star: ["вң¶", "вңё", "вң№", "вңә", "вң№", "вңё"],
  toggle: ["вҠ¶", "вҠ·"],
};

export interface SpinnerProps {
  style?: SpinnerStyle;
  label?: string;
  color?: string;
  fps?: number;
  /** Custom animation frames (overrides style). Default: undefined */
  frames?: string[];
}

export const Spinner = function Spinner({
  style: spinnerStyle = "dots",
  label,
  color,
  fps = 12,
  frames: customFrames,
}: SpinnerProps) {
  const theme = useTheme();
  const frame = useAnimation(fps);
  const frames = customFrames ?? FRAMES[spinnerStyle];
  const icon = frames[frame % frames.length];
  const resolvedColor = color ?? theme.colors.primary;

  return (
    <Text>
      <Text color={resolvedColor}>{icon}</Text>
      {label && <Text> {label}</Text>}
    </Text>
  );
};
